    // Using Pro for critical prompt generation
    const promptResponse = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: `Create a cinematic visual description for a summary of "${chapter.title}" in ${style} style. IMPORTANT: The output video MUST NOT contain any text, subtitles, captions, or watermarks. Focus entirely on purely visual storytelling and atmosphere.` }
        ]
      },
      config: {
        // Letting the model manage thinking tokens automatically for improved stability
      }
    });
    const videoPrompt = promptResponse.text || `Visual summary of ${chapter.title} in style of ${style}`;

    onStatus("Transmitting to Veo Core...");
    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: videoPrompt,
      config: {
        numberOfVideos: 1,
        resolution: resolution,
        aspectRatio: '16:9'
      }
    });

    while (!operation.done) {
      onStatus("Synthesizing temporal data...");
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({operation: operation});
    }

    onStatus("Finalizing transmission...");
    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  });
};

export const createChatSession = (file: FileContext, history: Content[] = []): Chat => {
  const ai = getAi();
  return ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: "You are a reading assistant. Answer questions strictly based on the provided document.",
      // Letting the model manage thinking tokens automatically for improved stability
    },
    history: [
      {
        role: 'user',
        parts: [getFilePart(file)]
      },
      ...history
    ]
  });
};

export const sendMessageToChat = async (chat: Chat, message: string | Part[]): Promise<string> => {
  return withRetry(async () => {
    const messageContent = typeof message === 'string' ? { message } : { message: { parts: message } };
    const response = await chat.sendMessage(messageContent as any);
    return response.text || "";
  });
};

import React, { useState, useEffect, useRef } from 'react';
import { Lightbulb, Image as ImageIcon, Download, RefreshCw, Settings2, Hexagon, Globe, Archive, PlayCircle, Play, Square, Maximize, Activity, Zap, Minimize2, Maximize2 } from 'lucide-react';
import { Concept, Chapter, FileContext } from '../types';
import { extractConcepts, generateConceptImage } from '../services/gemini';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
}

interface QuantumParticle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
  hue: number;
  alpha: number;
  life: number;
  type: 'node' | 'link' | 'pulse';
}

const STYLES = [
  'Digital Art', 'Cinematic', 'Anime', 'Photorealistic', 'Cartoon', 'Sketch', 
  'Cyberpunk', 'Vaporwave', 'Neon', 'Line Art', 'Low Poly', 'Isometric',
  '3D Render', 'Pixel Art'
];
const RATIOS = ['1:1', '16:9', '4:3', '9:16', '3:4', '2:3'];

export const Visualizer: React.FC<Props> = ({ chapter, fileContext }) => {
  const [concepts, setConcepts] = useState<Concept[]>([]);
  const [images, setImages] = useState<Record<string, string>>({});
  const [loadingImages, setLoadingImages] = useState<Record<string, boolean>>({});
  const [isInitializing, setIsInitializing] = useState(false);
  const [isGeneratingAll, setIsGeneratingAll] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);

  const [selectedStyle, setSelectedStyle] = useState('Cyberpunk');
  const [selectedRatio, setSelectedRatio] = useState('1:1');

  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const particlesRef = useRef<QuantumParticle[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  useEffect(() => {
    let mounted = true;
    const loadConcepts = async () => {
      setIsInitializing(true);
      try {
        const extracted = await extractConcepts(fileContext, chapter);
        if (mounted) setConcepts(extracted);
      } catch (err) {
        console.error(err);
      } finally {
        if (mounted) setIsInitializing(false);
      }
    };
    loadConcepts();
    return () => { mounted = false; };
  }, [chapter, fileContext]);

  // Visualizer Animation
  useEffect(() => {
    if (isMinimized || isInitializing) return;

    const initParticles = () => {
      const particles: QuantumParticle[] = [];
      for (let i = 0; i < 100; i++) {
        particles.push({
          x: Math.random() * 1800,
          y: Math.random() * 277,
          vx: (Math.random() - 0.5) * 1.2,
          vy: (Math.random() - 0.5) * 1.2,
          size: Math.random() * 1.5 + 0.5,
          hue: 180 + Math.random() * 40,
          alpha: Math.random() * 0.5 + 0.1,
          life: Math.random(),
          type: Math.random() > 0.8 ? 'node' : 'pulse'
        });
      }
      particlesRef.current = particles;
    };

    if (particlesRef.current.length === 0) initParticles();

    const draw = () => {
      if (canvasRef.current) {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.fillStyle = 'rgba(2, 4, 8, 0.15)';
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          // Draw Grid
          ctx.strokeStyle = 'rgba(0, 243, 255, 0.03)';
          ctx.lineWidth = 1;
          for (let x = 0; x < canvas.width; x += 40) {
            ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, canvas.height); ctx.stroke();
          }
          for (let y = 0; y < canvas.height; y += 40) {
            ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(canvas.width, y); ctx.stroke();
          }

          particlesRef.current.forEach((p, idx) => {
            p.life -= 0.0015;
            if (p.life <= 0) {
              p.life = 1;
              p.x = Math.random() * canvas.width;
              p.y = Math.random() * canvas.height;
            }

            p.x += p.vx;
            p.y += p.vy;

            // Screen wrap
            if (p.x < 0) p.x = canvas.width;
            if (p.x > canvas.width) p.x = 0;
            if (p.y < 0) p.y = canvas.height;
            if (p.y > canvas.height) p.y = 0;

            const alpha = p.life * p.alpha;
            ctx.fillStyle = `hsla(${p.hue}, 100%, 70%, ${alpha})`;

            if (p.type === 'node') {
              ctx.beginPath();
              ctx.arc(p.x, p.y, p.size * 2, 0, Math.PI * 2);
              ctx.fill();
              ctx.shadowBlur = 10;
              ctx.shadowColor = `hsla(${p.hue}, 100%, 50%, 0.5)`;
            } else {
              ctx.fillRect(p.x, p.y, p.size, p.size);
            }

            // Draw connections for nearby nodes
            particlesRef.current.slice(idx + 1, idx + 5).forEach(p2 => {
              const dx = p.x - p2.x;
              const dy = p.y - p2.y;
              const dist = Math.sqrt(dx * dx + dy * dy);
              if (dist < 100) {
                ctx.strokeStyle = `rgba(0, 243, 255, ${(1 - dist / 100) * 0.1 * p.life})`;
                ctx.beginPath();
                ctx.moveTo(p.x, p.y);
                ctx.lineTo(p2.x, p2.y);
                ctx.stroke();
              }
            });
          });
          ctx.shadowBlur = 0;
        }
      }
      animationRef.current = requestAnimationFrame(draw);
    };

    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isMinimized, isInitializing]);

