                      </div>
                  </div>
              </div>
              <div className="flex-2 flex justify-center">
                  <button onClick={handleToggleInitiate} className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[140px] justify-center ${isGeneratingAll ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}>{renderButtonIcon()}{renderButtonLabel()}</button>
