                        )}
                        </div>
                    )}
                    </div>
                    <div className="px-4 py-2 bg-black border-t border-zinc-900 flex items-center justify-between"><p className="text-[10px] text-zinc-600 truncate max-w-[80%] font-mono">{concept.visualPrompt}</p>{images[concept.term] && <div className="text-[10px] text-cyan-500 font-mono">RENDERED</div>}</div>
                </div>
                ))}
            </div>
       </div>
    </div>
  );
};

